  9	import AmpUI
 10	import AmpUIResources
 11	import SwiftUI
 12	
 13	public struct LibraryBadgesView: View {
 14	    let isNew: Bool?
 15	    let isNewTitleVisible: Bool
 16	    let isGenerated: Bool?
 17	    let isGeneratedTitleVisible: Bool
 18	    let isFavorite: Bool?
 19	    let isCompleted: Bool?
 20	    let isCompletedTitleVisible: Bool
 21	    let isChallenge: Bool?
 22	    let isChallengeTitleVisible: Bool
 23	    let isCommunityWorkout: Bool?
 24	    let isCommunityWorkoutTitleVisible: Bool
 25	
 26	    public init(isNew: Bool? = nil,
 27	                isNewTitleVisible: Bool = false,
 28	                isGenerated: Bool? = nil,
 29	                isGeneratedTitleVisible: Bool = false,
 30	                isFavorite: Bool? = nil,
 31	                isCompleted: Bool? = nil,
 32	                isCompletedTitleVisible: Bool = false,
 33	                isChallenge: Bool? = nil,
 34	                isChallengeTitleVisible: Bool = false,
 35	                isCommunityWorkout: Bool? = nil,
 36	                isCommunityWorkoutTitleVisible: Bool = false) {
 37	        self.isNew = isNew
 38	        self.isNewTitleVisible = isNewTitleVisible
 39	        self.isGenerated = isGenerated
 40	        self.isGeneratedTitleVisible = isGeneratedTitleVisible
 41	        self.isFavorite = isFavorite
 42	        self.isCompleted = isCompleted
 43	        self.isCompletedTitleVisible = isCompletedTitleVisible
 44	        self.isChallenge = isChallenge
 45	        self.isChallengeTitleVisible = isChallengeTitleVisible
 46	        self.isCommunityWorkout = isCommunityWorkout
 47	        self.isCommunityWorkoutTitleVisible = isCommunityWorkoutTitleVisible
 48	    }
 49	
 50	    public var body: some View {
 51	        HStack(spacing: Theme.Spacer.small) {
 52	            if self.isGenerated == true {
 53	                if self.isGeneratedTitleVisible {
 54	                    GeneratedAIBadge()
 55	                } else {
 56	                    BadgeView(style: .generated)
 57	                }
 58	            }
 59	
 60	            if self.isChallenge == true {
 61	                BadgeView(style: .challenge(withTitle: self.isChallengeTitleVisible))
 62	            }
 63	
 64	            if self.isCommunityWorkout == true {
 65	                BadgeView(style: .community(withTitle: self.isCommunityWorkoutTitleVisible))
 66	            }
 67	
 68	            if self.isNew == true && self.isGenerated != true && self.isCompleted != true {
 69	                BadgeView(style: .new(withTitle: self.isNewTitleVisible))
 70	            }
 71	
 72	            if self.isFavorite == true {
 73	                BadgeView(style: .favorite)
 74	            }
 75	
 76	            if self.isCompleted == true {
 77	                BadgeView(style: .completed(withTitle: self.isCompletedTitleVisible))
 78	            }
 79	        }
 80	    }
 81	}
